#[derive(Debug)]
pub enum TaskError {
    TaskNotFound(u32),
    EmptyTitle,
}

impl fmt::Display for TaskError {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        match self {
            TaskError::TaskNotFound(id) => write!(f, "task with id {} not found", id),
            TaskError::EmptyTitle => write!(f, "task title cannot be empty"),
        }
    }
}

impl Error for TaskError {}

impl TaskManager {
    pub fn new() -> Self {
        Self {
            tasks: Vec::new(),
            next_id: 1,
        }
    }

    pub fn add_task(
        &mut self,
        title: impl Into<String>,
        due_date: Option<DateTime<Local>>,
        tags: Option<Vec<String>>,
    ) -> Result<&Task, TaskError> {
        let title = title.into();

        if title.trim().is_empty() {
            return Err(TaskError::EmptyTitle);
        }

        let task = Task {
            id: self.next_id,
            title,
            completed: false,
            due_date,
            tags: tags.unwrap_or_default(),
        };

        self.tasks.push(task);
        self.next_id += 1;

        Ok(self.tasks.last().expect("task was just pushed"))
    }

    pub fn complete_task(&mut self, task_id: u32) -> Result<(), TaskError> {
        let task = self
            .tasks
            .iter_mut()
            .find(|task| task.id == task_id)
            .ok_or(TaskError::TaskNotFound(task_id))?;

        task.completed = true;
        Ok(())
    }

    pub fn get_overdue(&self) -> Vec<&Task> {
        let now = Local::now();

        self.tasks
            .iter()
            .filter(|task| {
                !task.completed
                    && task
                        .due_date
                        .as_ref()
                        .is_some_and(|due_date| *due_date < now)
            })
            .collect()
    }

    pub fn tasks(&self) -> &[Task] {
        &self.tasks
    }
}

fn main() -> Result<(), Box<dyn Error>> {
    let mut manager = TaskManager::new();

    manager.add_task("Write Rust version", None, Some(vec!["rust".into(), "coding".into()]))?;

    let overdue_date = Local::now() - chrono::Duration::days(1);
