use chrono::{DateTime, Local};
use std::fmt;
use thiserror::Error;

// ── Error Types ──────────────────────────────────────────────────────────────

#[derive(Debug, Error)]
pub enum TaskError {
    #[error("Task with id {0} not found")]
    NotFound(u32),

    #[error("Task with id {0} is already completed")]
    AlreadyCompleted(u32),

    #[error("Title cannot be empty")]
    EmptyTitle,
}

// ── Domain Types ─────────────────────────────────────────────────────────────

#[derive(Debug, Clone, PartialEq)]
pub struct Task {
    pub id: u32,
    pub title: String,
    pub completed: bool,
    pub due_date: Option<DateTime<Local>>,
    pub tags: Vec<String>,
}

impl Task {
    /// Returns true if the task is past its due date and not yet completed.
    pub fn is_overdue(&self) -> bool {
        self.due_date
            .map(|due| !self.completed && due < Local::now())
            .unwrap_or(false)
    }
}

impl fmt::Display for Task {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        let status = if self.completed { "✓" } else { "○" };
        let due = self
            .due_date
            .map(|d| d.format("%Y-%m-%d %H:%M").to_string())
            .unwrap_or_else(|| "no due date".to_string());

        write!(
            f,
            "[{}] #{} \"{}\" (due: {}, tags: [{}])",
            status,
            self.id,
            self.title,
            due,
            self.tags.join(", ")
        )
    }
}

// ── Builder for ergonomic task creation ──────────────────────────────────────

/// Used to configure a new task before adding it to the manager.
#[derive(Debug, Default)]
pub struct TaskBuilder {
    title: String,
    due_date: Option<DateTime<Local>>,
    tags: Vec<String>,
}

impl TaskBuilder {
    pub fn new(title: impl Into<String>) -> Self {
        Self {
            title: title.into(),
            ..Default::default()
        }
    }

    pub fn due_date(mut self, date: DateTime<Local>) -> Self {
        self.due_date = Some(date);
        self
    }

    pub fn tag(mut self, tag: impl Into<String>) -> Self {
        self.tags.push(tag.into());
        self
    }

    pub fn tags(mut self, tags: impl IntoIterator<Item = impl Into<String>>) -> Self {
        self.tags.extend(tags.into_iter().map(Into::into));
        self
    }
}

// ── Task Manager ─────────────────────────────────────────────────────────────

#[derive(Debug, Default)]
pub struct TaskManager {
    tasks: Vec<Task>,
    next_id: u32,
}

impl TaskManager {
    pub fn new() -> Self {
        Self {
            tasks: Vec::new(),
            next_id: 1,
        }
    }

    /// Adds a task built from a [`TaskBuilder`], returning a reference to it.
    ///
    /// # Errors
    /// Returns [`TaskError::EmptyTitle`] if the title is blank.
    pub fn add_task(&mut self, builder: TaskBuilder) -> Result<&Task, TaskError> {
        let title = builder.title.trim().to_string();
        if title.is_empty() {
            return Err(TaskError::EmptyTitle);
        }

        let task = Task {
            id: self.next_id,
            title,
            completed: false,
            due_date: builder.due_date,
            tags: builder.tags,
        };

        self.tasks.push(task);
        self.next_id += 1;

        // Safe: we just pushed, so last() always returns Some.
        Ok(self.tasks.last().expect("task was just pushed"))
    }

    /// Marks a task as completed.
    ///
    /// # Errors
    /// - [`TaskError::NotFound`] if no task with `task_id` exists.
    /// - [`TaskError::AlreadyCompleted`] if the task is already done.
    pub fn complete_task(&mut self, task_id: u32) -> Result<&Task, TaskError> {
        let task = self
            .tasks
            .iter_mut()
            .find(|t| t.id == task_id)
            .ok_or(TaskError::NotFound(task_id))?;

        if task.completed {
            return Err(TaskError::AlreadyCompleted(task_id));
        }

        task.completed = true;
        Ok(task)
    }

    /// Returns references to all tasks that are past their due date and incomplete.
    pub fn overdue_tasks(&self) -> Vec<&Task> {
        self.tasks.iter().filter(|t| t.is_overdue()).collect()
    }

    /// Returns a reference to a task by id.
    pub fn get_task(&self, task_id: u32) -> Option<&Task> {
        self.tasks.iter().find(|t| t.id == task_id)
    }

    /// Returns references to all tasks, in insertion order.
    pub fn all_tasks(&self) -> &[Task] {
        &self.tasks
    }

    /// Returns the number of tasks currently managed.
    pub fn len(&self) -> usize {
        self.tasks.len()
    }

    pub fn is_empty(&self) -> bool {
        self.tasks.is_empty()
    }
}

// ── Demo ─────────────────────────────────────────────────────────────────────

fn main() -> Result<(), TaskError> {
    let mut manager = TaskManager::new();

    // Add tasks using the builder pattern.
    let task1 = manager
        .add_task(TaskBuilder::new("Write documentation").tag("docs").tag("writing"))?
        .clone();

