//! A tiny in‑memory task manager.
//!
//! The API mirrors the behaviour of the original Python implementation
//! while embracing Rust’s safety and ergonomics.

use chrono::{DateTime, Utc};
use thiserror::Error;

/// A single to‑do item.
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Task {
    /// Unique identifier (assigned by `TaskManager`).
    id: u32,
    /// Human‑readable title.
    title: String,
    /// Has the task been completed?
    completed: bool,
    /// Optional deadline.
    due_date: Option<DateTime<Utc>>,
    /// Arbitrary tags.
    tags: Vec<String>,
}

impl Task {
    /// Create a new `Task`. This is used internally by `TaskManager`.
    fn new(
        id: u32,
        title: impl Into<String>,
        due_date: Option<DateTime<Utc>>,
        tags: Vec<String>,
    ) -> Self {
        Self {
            id,
            title: title.into(),
            completed: false,
            due_date,
            tags,
        }
    }

    // -----------------------------------------------------------------
    // Public getters – the fields are kept private to keep the invariant
    // that `completed` can only be changed via `TaskManager::complete_task`.
    // -----------------------------------------------------------------
    pub fn id(&self) -> u32 {
        self.id
    }

    pub fn title(&self) -> &str {
        &self.title
    }

    pub fn completed(&self) -> bool {
        self.completed
    }

    pub fn due_date(&self) -> Option<DateTime<Utc>> {
        self.due_date
    }

    pub fn tags(&self) -> &[String] {
        &self.tags
    }

    /// Mark the task as completed.
    fn set_completed(&mut self, completed: bool) {
        self.completed = completed;
    }
}

/// Errors that can arise while operating on a `TaskManager`.
#[derive(Debug, Error, PartialEq, Eq)]
pub enum TaskError {
    /// The supplied identifier does not correspond to any stored task.
    #[error("task with id {0} not found")]
    NotFound(u32),

    /// The caller tried to add a task with an empty title.
    #[error("task title must not be empty")]
    EmptyTitle,
}

/// In‑memory collection of tasks.
#[derive(Debug, Default)]
pub struct TaskManager {
    tasks: Vec<Task>,
    next_id: u32,
}

impl TaskManager {
    /// Construct a fresh manager.
    ///
    /// The manager starts empty and will assign identifiers starting at `1`.
    pub fn new() -> Self {
        Self {
            tasks: Vec::new(),
            next_id: 1,
        }
    }

    /// Add a new task.
    ///
    /// * `title` – non‑empty description of the task.
    /// * `due_date` – optional deadline.
    /// * `tags` – optional list of tags (empty vector if `None`).
    ///
    /// Returns the created `Task` on success or a `TaskError` if the title
    /// is empty.
    pub fn add_task(
        &mut self,
        title: impl Into<String>,
        due_date: Option<DateTime<Utc>>,
        tags: Option<Vec<String>>,
    ) -> Result<Task, TaskError> {
        let title_str = title.into();
        if title_str.trim().is_empty() {
            return Err(TaskError::EmptyTitle);
        }

        let task = Task::new(self.next_id, title_str, due_date, tags.unwrap_or_default());
        self.tasks.push(task.clone());
        self.next_id += 1;
        Ok(task)
    }

    /// Mark the task with `task_id` as completed.
    ///
    /// Returns `Ok(())` on success or `Err(TaskError::NotFound(_))` if the id
    /// does not exist.
    pub fn complete_task(&mut self, task_id: u32) -> Result<(), TaskError> {
        // `iter_mut` gives us mutable references to the stored tasks.
        for task in self.tasks.iter_mut() {
            if task.id() == task_id {
                task.set_completed(true);
                return Ok(());
            }
        }
        Err(TaskError::NotFound(task_id))
    }

    /// Return a vector of **overdue** tasks.
    ///
    /// An overdue task is one that has a `due_date` in the past **and**
    /// is not yet completed.
    pub fn get_overdue(&self) -> Vec<Task> {
        let now = Utc::now();
        self.tasks
            .iter()
            .filter(|t| {
                t.due_date()
                    .map(|d| d < now)
                    .unwrap_or(false) && !t.completed()
            })
            .cloned()
            .collect()
    }

    // -----------------------------------------------------------------
    // Additional convenience methods (not present in the original Python
    // code but useful for a real library). They are kept private to the
    // crate because they are not required for the translation.
    // -----------------------------------------------------------------
    #[allow(dead_code)]
    fn get_all(&self) -> &[Task] {
        &self.tasks
    }
}

