    }

    #[test]
    fn overdue_detection() {
        let mut mgr = TaskManager::new();

        // Past due date → overdue
        let past = Utc.ymd(2000, 1, 1).and_hms(0, 0, 0);
        mgr.add_task("Old task", Some(past), None).unwrap();

        // Future due date → not overdue
        let future = Utc::now() + chrono::Duration::days(10);
        mgr.add_task("Future task", Some(future), None).unwrap();

        // No due date → never overdue
        mgr.add_task("No due date", None, None).unwrap();

