```rust
use chrono::{DateTime, Local};

#[derive(Debug, Clone)]
pub struct Task {
    pub id: u32,
    pub title: String,
    pub completed: bool,
    pub due_date: Option<DateTime<Local>>,
    pub tags: Vec<String>,
}

pub struct TaskManager {
    tasks: Vec<Task>,
    next_id: u32,
}

impl TaskManager {
    pub fn new() -> Self {
        Self {
            tasks: Vec::new(),
            next_id: 1,
        }
    }

    pub fn add_task(
        &mut self,
        title: String,
        due_date: Option<DateTime<Local>>,
        tags: Option<Vec<String>>,
    ) -> &Task {
        let task = Task {
            id: self.next_id,
            title,
            completed: false,
            due_date,
            tags: tags.unwrap_or_default(),
        };

        self.tasks.push(task);
        self.next_id += 1;

        // Return a reference to the last inserted element
        self.tasks.last().unwrap()
    }

    pub fn complete_task(&mut self, task_id: u32) -> bool {
        if let Some(task) = self.tasks.iter_mut().find(|t| t.id == task_id) {
            task.completed = true;
            return true;
        }
        false
    }

    pub fn get_overdue(&self) -> Vec<&Task> {
        let now = Local::now();
        self.tasks
            .iter()
            .filter(|t| {
                !t.completed && t.due_date.map_or(false, |date| date < now)
            })
            .collect()
    }
}

fn main() {
    let mut manager = TaskManager::new();

    manager.add_task(
        "Finish Rust project".to_string(),
        Some(Local::now()), 
        Some(vec!["rust".to_string(), "coding".to_string()])
    );

    let success = manager.complete_task(1);
    println!("Task 1 completed: {}", success);

    let overdue = manager.get_overdue();
    println!("Overdue tasks count: {}", overdue.len());
}
