use chrono::{DateTime, Utc};
use std::error::Error;
use std::fmt;

// 1. Define the Task Struct
// We derive Clone because we will replace tasks in the vector rather than mutating them in place.
// We derive Debug to allow printing/inspecting the struct.
#[derive(Debug, Clone, PartialEq)]
pub struct Task {
    pub id: u64,
    pub title: String,
    pub completed: bool,
    pub due_date: Option<DateTime<Utc>>,
    pub tags: Vec<String>,
}

// 2. Define a custom Error type for better error handling
#[derive(Debug, PartialEq)]
pub enum TaskError {
    NotFound(u64),
}

impl fmt::Display for TaskError {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        match self {
            TaskError::NotFound(id) => write!(f, "Task with id {} not found", id),
        }
    }
}

impl Error for TaskError {}

// 3. Define the TaskManager
#[derive(Debug, Default)]
pub struct TaskManager {
    tasks: Vec<Task>,
    next_id: u64,
}

impl TaskManager {
    pub fn new() -> Self {
        Self {
            tasks: Vec::new(),
            next_id: 1,
        }
    }

    /// Adds a new task.
    /// Uses Into<String> for title to accept both &str and String efficiently.
    /// Uses impl IntoIterator for tags to accept Vec<String>, &[&str], or even empty arrays.
    pub fn add_task<T, I>(&mut self, title: T, due_date: Option<DateTime<Utc>>, tags: I) -> Task
    where
        T: Into<String>,
        I: IntoIterator<Item = String>,
    {
        let task = Task {
            id: self.next_id,
            title: title.into(),
            completed: false,
            due_date,
            tags: tags.into_iter().collect(),
        };

        self.next_id += 1;

        // We clone here to return a copy to the caller, while the manager keeps ownership.
        let task_clone = task.clone();
        self.tasks.push(task);

        task_clone
    }

    /// Marks a task as completed.
    /// Returns Result to handle the case where the ID doesn't exist.
    pub fn complete_task(&mut self, task_id: u64) -> Result<(), TaskError> {
        // We find the index first to avoid borrowing issues
        if let Some(index) = self.tasks.iter().position(|t| t.id == task_id) {
            // We clone the task, modify the clone, and swap it into the vector.
            // This is a safe way to satisfy Rust's borrowing rules.
            let mut task = self.tasks[index].clone();
            task.completed = true;
            self.tasks[index] = task;
            Ok(())
        } else {
            Err(TaskError::NotFound(task_id))
        }
    }

    /// Returns a vector of references to overdue tasks.
    /// Uses references (&Task) to avoid unnecessary cloning of data.
    pub fn get_overdue(&self) -> Vec<&Task> {
        let now = Utc::now();
        self.tasks
            .iter()
            .filter(|t| {
                // Check if due_date exists, is before now, and task is not completed
                t.due_date
                    .map_or(false, |due| due < now && !t.completed)
            })
            .collect()
    }
}

