    use super::*;
    use chrono::{Duration, SubsecRound};

    #[test]
    fn test_add_and_complete() {
        let mut manager = TaskManager::new();

        // Add a task
        let task = manager.add_task("Buy Milk", None, vec!["home".to_string()]);
        assert_eq!(task.id, 1);
        assert_eq!(task.title, "Buy Milk");
        assert!(!task.completed);

        // Complete the task
        let result = manager.complete_task(1);
        assert!(result.is_ok());

        // Verify it is completed in the manager
        let updated_task = &manager.tasks[0];
        assert!(updated_task.completed);
    }

    #[test]
    fn test_complete_nonexistent() {
        let mut manager = TaskManager::new();
        let result = manager.complete_task(999);

        // Pattern match on the specific error
        match result {
            Err(TaskError::NotFound(id)) => assert_eq!(id, 999),
            _ => panic!("Expected NotFound error"),
        }
    }

    #[test]
    fn test_get_overdue() {
        let mut manager = TaskManager::new();
        let now = Utc::now().round_subsecs(0); // Truncate microseconds for clean comparison

        // 1. Overdue task
        let past = now - Duration::hours(1);
        manager.add_task("Past Task", Some(past), vec![]);

        // 2. Future task (should not appear)
        let future = now + Duration::hours(1);
        manager.add_task("Future Task", Some(future), vec![]);

        // 3. Completed task that is overdue (should not appear)
        let mut completed_task = manager.add_task("Done Past", Some(past), vec![]);
        manager.complete_task(completed_task.id).unwrap();

        // 4. Task with no due date (should not appear)
        manager.add_task("No Due", None, vec![]);

        let overdue = manager.get_overdue();

        assert_eq!(overdue.len(), 1);
        assert_eq!(overdue[0].title, "Past Task");
    }

