        manager.add_task("Task 2", None, vec![]);

        // Since we used impl IntoIterator<Item = String>, we can't pass &str directly 
        // without a helper, but we can easily map it. 
        // However, to make it truly ergonomic, we can rely on the caller to convert.

        assert_eq!(manager.tasks.len(), 2);
    }
